import{c as e,Q as i,j as a,m as t}from"./chunks/framework.DVkeSyfh.js";const k=JSON.parse('{"title":"Installation","description":"","frontmatter":{},"headers":[],"relativePath":"install.md","filePath":"install.md","lastUpdated":1780022874000}'),n={name:"install.md"};function d(l,s,h,o,r,p){return i(),a("div",null,[...s[0]||(s[0]=[t(`<h1 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h1><p>This page covers how to install <code>dj-track-similarity</code> locally, including the optional dependency groups, the verified Windows CUDA stack, and the FFmpeg requirement. Read it before the first run, then use <a href="./cli.html">CLI</a> to scan a folder and start the server.</p><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Notes</th></tr></thead><tbody><tr><td>Python <code>&gt;= 3.10</code></td><td>The backend and CLI target Python 3.10 or newer.</td></tr><tr><td>FFmpeg</td><td>Required for server startup and audio decoding. Must be on <code>PATH</code> or set through <code>DJ_TRACK_SIMILARITY_FFMPEG</code>.</td></tr><tr><td>CUDA GPU</td><td>Optional. Speeds up MAEST, MERT, and CLAP. CPU works without a GPU.</td></tr></tbody></table><p>The project installs the <code>dj-sim</code> command from <code>pyproject.toml</code>. After install, <code>dj-sim doctor</code> reports the Python, PyTorch, and CUDA runtime it sees.</p><h2 id="dependency-groups" tabindex="-1">Dependency Groups <a class="header-anchor" href="#dependency-groups" aria-label="Permalink to &quot;Dependency Groups&quot;">​</a></h2><p>Core dependencies (<code>numpy</code>, <code>mutagen</code>, <code>pydantic</code>, <code>typer</code>, <code>fastapi</code>, <code>uvicorn</code>, <code>joblib</code>) install with the base package. Optional extras enable the analysis families and the local lab:</p><table tabindex="0"><thead><tr><th>Group</th><th>Installs</th><th>Enables</th></tr></thead><tbody><tr><td><code>sonara</code></td><td>Sonara support</td><td>Sonara playlist feature extraction and SONARA search.</td></tr><tr><td><code>ml</code></td><td>PyTorch/Torchaudio/Torchvision/TorchCodec, Transformers, Hugging Face Hub, LAION-CLAP, MAEST</td><td>MAEST genre analysis, MERT embeddings, CLAP audio/text embeddings.</td></tr><tr><td><code>rhythm-lab</code></td><td>scikit-learn</td><td>Local classifier training and benchmarking in Rhythm Lab.</td></tr><tr><td><code>dev</code></td><td>pytest, Ruff</td><td>Tests and linting.</td></tr></tbody></table><p>Combine the groups you need, for example <code>.[sonara,ml,dev]</code> for the full local analysis stack without Rhythm Lab training, or <code>.[sonara,ml,rhythm-lab,dev]</code> when the same environment will also train classifier profiles.</p><h2 id="base-install" tabindex="-1">Base Install <a class="header-anchor" href="#base-install" aria-label="Permalink to &quot;Base Install&quot;">​</a></h2><p>For a development checkout, install the project in editable mode:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">m pip install </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;.[dev]&quot;</span></span></code></pre></div><p>This is enough to run the CLI, the server, scanning, search, and exports. Analysis families that need machine-learning models additionally require the <code>sonara</code> and <code>ml</code> groups described below.</p><h2 id="ml-stack-cuda-windows" tabindex="-1">ML Stack (CUDA, Windows) <a class="header-anchor" href="#ml-stack-cuda-windows" aria-label="Permalink to &quot;ML Stack (CUDA, Windows)&quot;">​</a></h2><p>The verified Windows CUDA stack is:</p><table tabindex="0"><thead><tr><th>Component</th><th>Version</th></tr></thead><tbody><tr><td>PyTorch</td><td><code>2.11.0</code></td></tr><tr><td>Torchaudio</td><td><code>2.11.0</code></td></tr><tr><td>Torchvision</td><td><code>0.26.0</code></td></tr><tr><td>TorchCodec</td><td><code>0.13.0</code></td></tr><tr><td>NumPy</td><td><code>&gt;=1.26,&lt;2.0</code></td></tr><tr><td>PyTorch wheel index</td><td><code>https://download.pytorch.org/whl/cu130</code></td></tr></tbody></table><p>Install the matching CUDA wheels from the official PyTorch wheel index first, then install the remaining ML dependencies:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">m pip install torch</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">==</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2.11</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> torchvision</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">==</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.26</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> torchaudio</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">==</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2.11</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">index</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">url https:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">download.pytorch.org</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">whl</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cu130</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">m pip install torchcodec</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">==</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.13</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">index</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">url https:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">download.pytorch.org</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">whl</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cu130</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">m pip install </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;.[sonara,ml,dev]&quot;</span></span></code></pre></div><p>Use <code>.[sonara,ml,rhythm-lab,dev]</code> instead when the same environment will also train Rhythm Lab classifier profiles.</p><blockquote><p>Warning: keep the PyTorch, Torchaudio, Torchvision, and TorchCodec versions synchronized with the CUDA wheel index above, and keep <code>numpy</code> below <code>2.0</code>. Mixing versions is the most common cause of import or decode failures.</p></blockquote><h2 id="ffmpeg" tabindex="-1">FFmpeg <a class="header-anchor" href="#ffmpeg" aria-label="Permalink to &quot;FFmpeg&quot;">​</a></h2><p><code>ffmpeg</code> is required for robust server startup and shared audio decoding. It is found from <code>PATH</code> or configured with:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DJ_TRACK_SIMILARITY_FFMPEG</span></span></code></pre></div><p>On Windows, TorchCodec-backed Torchaudio decoding needs an FFmpeg <strong>shared</strong> build with DLLs on <code>PATH</code>, not only a static <code>ffmpeg.exe</code>. The verified portable build is GyanD <code>ffmpeg 8.1.1-full_build-shared</code>, with a layout such as:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>C:\\Utils\\tools\\ffmpeg\\bin\\ffmpeg.exe</span></span>
<span class="line"><span>C:\\Utils\\tools\\ffmpeg\\bin\\avcodec-*.dll</span></span>
<span class="line"><span>C:\\Utils\\tools\\ffmpeg\\bin\\avformat-*.dll</span></span></code></pre></div><blockquote><p>Warning: a static <code>ffmpeg.exe</code> alone is not enough for TorchCodec decoding on Windows. Make sure the <code>bin</code> folder with the <code>av*.dll</code> files is on <code>PATH</code>.</p></blockquote><h2 id="cpu-only-install" tabindex="-1">CPU-Only Install <a class="header-anchor" href="#cpu-only-install" aria-label="Permalink to &quot;CPU-Only Install&quot;">​</a></h2><p>A GPU is not required. Install the same <code>sonara</code> and <code>ml</code> groups, but you can skip the CUDA wheel index and let PyTorch install its default build:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">m pip install </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;.[sonara,ml,dev]&quot;</span></span></code></pre></div><p>Analysis then runs on CPU. Use <code>--device cpu</code> (or leave <code>--device auto</code>, which selects CPU when no GPU is visible) for MAEST, MERT, and CLAP work.</p><h2 id="verify-the-install" tabindex="-1">Verify the Install <a class="header-anchor" href="#verify-the-install" aria-label="Permalink to &quot;Verify the Install&quot;">​</a></h2><p>Check the command and the runtime:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">dj</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sim </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">help</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">dj</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sim doctor</span></span></code></pre></div><p><code>dj-sim doctor</code> prints the detected Python and PyTorch versions, whether CUDA is available, and the device <code>auto</code> would choose. Use it whenever <code>auto</code>, <code>cpu</code>, or <code>cuda</code> behavior is unclear, or after changing Python packages, CUDA wheels, drivers, or the FFmpeg/TorchCodec setup. See <a href="./cli.html">CLI</a> for the full <code>doctor</code> output.</p><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li>Read the <a href="./overview.html">Overview</a> for the typical workflow.</li><li>Use <a href="./cli.html">CLI</a> to scan a folder and start the server.</li><li>See <a href="./models.html">Models</a> for what each model does and which extras it needs, and <a href="./analysis.html">Analysis</a> to decide which pass to run first.</li></ul>`,36)])])}const g=e(n,[["render",d]]);export{k as __pageData,g as default};
